FROM jsonb_to_recordset('[{"id": "cap-106-society-058", "exam_id": "cap", "subject_id": "sub-cap-social", "paper_id": "cap-106-society", "question_type": "single_choice", "question_text": "根據上文雙底線處的內容判斷，畢道文的作為，最可能是符合馬斯洛需求層\n次理論的哪一層次？", "options": ["生理需求           & 需求層次理論＝個人需求層次理論", "安全需求", "尊重需求", "自我實現需求 閱讀下列選文，回答第 59 至 60 題： 臺灣的電線桿或配電箱，大多標有由英文 字母和數字組成的雙排編號，共9碼或11碼，此 編號為「電力坐標」，如圖(二十四)所示。坐標 中的英文字母和數字乃根據固定的規則編碼， 例如第一個英文字母代表分區坐標區塊，對照 圖(二十五)即可大略知道位於臺灣何處。電力坐       圖(二十四) 標經過簡單的換算，可以轉換成臺灣常用的坐 標系統。因此，民眾只要向救難單位報出電力 坐標，救難人員就可依此坐標精準確認地點。                    圖(二十五)"], "correct_answer": 3, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:38+00:00", "source_pdf_sha1": "3dae370215e1", "answer_pdf_sha1": "0fa526cf1539", "flags": ["needs_image"], "parse_confidence": 0.85, "original_question_number": 58, "raw_text": "58. 根據上文雙底線處的內容判斷，畢道文的作為，最可能是符合馬斯洛需求層\n    次理論的哪一層次？\n    (A)生理需求           & 需求層次理論＝個人需求層次理論\n    (B)安全需求\n    (C)尊重需求\n    (D)自我實現需求\n\n\n\n閱讀下列選文，回答第 59 至 60 題：\n   臺灣的電線桿或配電箱，大多標有由英文\n字母和數字組成的雙排編號，共9碼或11碼，此\n編號為「電力坐標」，如圖(二十四)所示。坐標\n中的英文字母和數字乃根據固定的規則編碼，\n例如第一個英文字母代表分區坐標區塊，對照\n圖(二十五)即可大略知道位於臺灣何處。電力坐       圖(二十四)\n標經過簡單的換算，可以轉換成臺灣常用的坐\n標系統。因此，民眾只要向救難單位報出電力\n坐標，救難人員就可依此坐標精準確認地點。                    圖(二十五)"}, "is_active": false, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-106-society-059", "exam_id": "cap", "subject_id": "sub-cap-social", "paper_id": "cap-106-society", "question_type": "single_choice", "question_text": "位置的表示法可分為絕對位置和相對位置。上文介紹電線桿上的編號與下列\n何者的表示法相同？", "options": ["綠島位在墾丁國家公園的東北方", "彰化車站距離員林車站15公里", "東華大學位在花蓮縣 壽豐鄉 大學路二段1號", "臺北市政府大樓位在101大樓北方300公尺處"], "correct_answer": 2, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:38+00:00", "source_pdf_sha1": "3dae370215e1", "answer_pdf_sha1": "0fa526cf1539", "flags": [], "parse_confidence": 1.0, "original_question_number": 59, "raw_text": "59. 位置的表示法可分為絕對位置和相對位置。上文介紹電線桿上的編號與下列\n    何者的表示法相同？\n    (A)綠島位在墾丁國家公園的東北方\n    (B)彰化車站距離員林車站15公里\n    (C)東華大學位在花蓮縣 壽豐鄉 大學路二段1號\n    (D)臺北市政府大樓位在101大樓北方300公尺處\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-106-society-060", "exam_id": "cap", "subject_id": "sub-cap-social", "paper_id": "cap-106-society", "question_type": "single_choice", "question_text": "圖(二十四)電線桿上的編號對照圖(二十五)判斷，其位在下列何處的可能性最高？", "options": ["苗栗縣", "桃園市", "嘉義縣", "雲林縣 閱讀下列選文，回答第 61 至 63 題： 知名紀錄片《看見臺灣》，以直升機空拍的創新手法拍攝，讓觀眾深受震撼 與感動，許多民眾也起而效法想運用空拍機來記錄生活的點滴，使得空拍機一時 成為市場上的熱銷商品。 空拍機自由飛行、突破地表障礙的特性雖然迷人，但最近因有民眾使用空拍 機時，違反了《民用航空法》而遭到主管機關開罰，此一事件引發社會大眾關切 空拍機可能侵犯隱私、失控墜落、影響飛安等問題，也凸顯現有法令尚未完備， 因此各界呼籲中央政府機關應盡速通過三讀程序，修訂相關法律加以規範。"], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:38+00:00", "source_pdf_sha1": "3dae370215e1", "answer_pdf_sha1": "0fa526cf1539", "flags": ["needs_image"], "parse_confidence": 0.85, "original_question_number": 60, "raw_text": "60. 圖(二十四)電線桿上的編號對照圖(二十五)判斷，其位在下列何處的可能性最高？\n    (A)苗栗縣    (B)桃園市  (C)嘉義縣   (D)雲林縣\n\n閱讀下列選文，回答第 61 至 63 題：\n  知名紀錄片《看見臺灣》，以直升機空拍的創新手法拍攝，讓觀眾深受震撼\n與感動，許多民眾也起而效法想運用空拍機來記錄生活的點滴，使得空拍機一時\n成為市場上的熱銷商品。\n  空拍機自由飛行、突破地表障礙的特性雖然迷人，但最近因有民眾使用空拍\n機時，違反了《民用航空法》而遭到主管機關開罰，此一事件引發社會大眾關切\n空拍機可能侵犯隱私、失控墜落、影響飛安等問題，也凸顯現有法令尚未完備，\n因此各界呼籲中央政府機關應盡速通過三讀程序，修訂相關法律加以規範。"}, "is_active": false, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-106-society-061", "exam_id": "cap", "subject_id": "sub-cap-social", "paper_id": "cap-106-society", "question_type": "single_choice", "question_text": "文中第一段所呈現的市場變化，將最先反應在圖\n(二十六)中的那一區段？", "options": ["甲", "乙", "丙", "丁"], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:38+00:00", "source_pdf_sha1": "3dae370215e1", "answer_pdf_sha1": "0fa526cf1539", "flags": ["needs_image"], "parse_confidence": 0.85, "original_question_number": 61, "raw_text": "61. 文中第一段所呈現的市場變化，將最先反應在圖\n    (二十六)中的那一區段？\n    (A)甲   (B)乙  (C)丙 (D)丁\n"}, "is_active": false, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-106-society-062", "exam_id": "cap", "subject_id": "sub-cap-social", "paper_id": "cap-106-society", "question_type": "single_choice", "question_text": "關於文中遭開罰者「所應負起之責任類型」與\n「權利救濟方式」的搭配，下列何者正確？", "options": ["刑事責任，聲請調解", "刑事責任，提起訴訟", "行政責任，提起訴願", ""], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:38+00:00", "source_pdf_sha1": "3dae370215e1", "answer_pdf_sha1": "0fa526cf1539", "flags": ["needs_image", "option_incomplete"], "parse_confidence": 0.6, "original_question_number": 62, "raw_text": "62. 關於文中遭開罰者「所應負起之責任類型」與\n    「權利救濟方式」的搭配，下列何者正確？\n    (A)刑事責任，聲請調解 (B)刑事責任，提起訴訟\n    (C)行政責任，提起訴願 (D)行政責任，提出請願         圖(二十六)\n"}, "is_active": false, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-106-society-063", "exam_id": "cap", "subject_id": "sub-cap-social", "paper_id": "cap-106-society", "question_type": "single_choice", "question_text": "文末所提及的中央政府機關，其職權包括下列何者？", "options": ["提出糾正案", "提出不信任案", "依法律推行政策", "統一解釋法律命令"], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:38+00:00", "source_pdf_sha1": "3dae370215e1", "answer_pdf_sha1": "0fa526cf1539", "flags": ["no_answer"], "parse_confidence": 1.0, "original_question_number": 63, "raw_text": "63. 文末所提及的中央政府機關，其職權包括下列何者？\n    (A)提出糾正案    (B)提出不信任案\n    (C)依法律推行政策  (D)統一解釋法律命令\n\n"}, "is_active": false, "auto_gradable": false, "difficulty": 3, "explanation": null}]'::jsonb) AS t(
